typedef enum SDL_BlendOperation
{
 SDL_BLENDOPERATION_ADD = 0x1, /**< تشير هذه القيمة إلى أن SDL يجمع مساهمتي المصدر والوجهة عند تنفيذ عملية المزج. */
 SDL_BLENDOPERATION_SUBTRACT = 0x2, /**< تشير هذه القيمة إلى أن SDL يطرح مساهمة الوجهة من مساهمة المصدر عند تنفيذ عملية المزج. */
 SDL_BLENDOPERATION_REV_SUBTRACT = 0x3, /**< تشير هذه القيمة إلى أن SDL يطرح مساهمة المصدر من مساهمة الوجهة عند تنفيذ عملية المزج. */
 SDL_BLENDOPERATION_MINIMUM = 0x4, /**< تشير هذه القيمة إلى أن SDL يختار القيمة الدنيا بين المصدر والوجهة عند تنفيذ عملية المزج. */
 SDL_BLENDOPERATION_MAXIMUM = 0x5 /**< تشير هذه القيمة إلى أن SDL يختار القيمة العليا بين المصدر والوجهة عند تنفيذ عملية المزج. */
} SDL_BlendOperation;
